/* host_charmap.c - ASCII to Pokemon character encoding
 *
 * On GBA, the assembler preprocessor converts _("text") literals
 * from ASCII to Pokemon encoding via charmap.txt. On native, the
 * C compiler sees plain ASCII. This converts at runtime.
 * Lookup table auto-generated from charmap.txt.
 */

#include "global.h"

static const u8 sAsciiToPokemon[128] = {
    0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0xFE, 0x00, 0x00, 0x00, 0x00, 0x00,
    0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
    0x00, 0xAB, 0x00, 0x00, 0xFF, 0x5B, 0x2D, 0x00, 0x5C, 0x5D, 0x00, 0x2E, 0xB8, 0xAE, 0xAD, 0xBA,
    0xA1, 0xA2, 0xA3, 0xA4, 0xA5, 0xA6, 0xA7, 0xA8, 0xA9, 0xAA, 0xF0, 0x36, 0x85, 0x00, 0x86, 0xAC,
    0x00, 0xBB, 0xBC, 0xBD, 0xBE, 0xBF, 0xC0, 0xC1, 0xC2, 0xC3, 0xC4, 0xC5, 0xC6, 0xC7, 0xC8, 0xC9,
    0xCA, 0xCB, 0xCC, 0xCD, 0xCE, 0xCF, 0xD0, 0xD1, 0xD2, 0xD3, 0xD4, 0x00, 0x00, 0x00, 0x00, 0x00,
    0x00, 0xD5, 0xD6, 0xD7, 0xD8, 0xD9, 0xDA, 0xDB, 0xDC, 0xDD, 0xDE, 0xDF, 0xE0, 0xE1, 0xE2, 0xE3,
    0xE4, 0xE5, 0xE6, 0xE7, 0xE8, 0xE9, 0xEA, 0xEB, 0xEC, 0xED, 0xEE, 0x00, 0x00, 0x00, 0x00, 0x00,
};

const u8 *HostCharmapConvert(u8 *str)
{
    /* Already converted if first byte is outside ASCII printable range */
    if (str[0] > 0x7E || str[0] == 0x00)
        return str;
    u8 *p = str;
    while (*p != 0x00) {
        u8 c = *p;
        if (c == '$') { *p = 0xFF; return str; }
        if (c < 128) *p = sAsciiToPokemon[c];
        p++;
    }
    /* C null terminator -> Pokemon EOS (0xFF) */
    *p = 0xFF;
    return str;
}
